--
-- Name: telco_cleaned; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.telco_cleaned AS
 SELECT "CustomerID",
    "Gender",
    "Senior Citizen",
    "Tenure Months",
    "Internet Service",
    "Contract",
    "Payment Method",
    "Monthly Charges",
    (NULLIF(TRIM(BOTH FROM "Total Charges"), ''::text))::numeric(10,2) AS total_charges_fixed,
    "Churn Value",
    "Churn Score",
    "CLTV",
    "Churn Reason"
   FROM public.telco_churn
  WHERE ("Total Charges" IS NOT NULL);


ALTER VIEW public.telco_cleaned OWNER TO postgres;

--
-- Name: early_churn_window; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.early_churn_window AS
 SELECT
        CASE
            WHEN ("Tenure Months" <= 6) THEN '0-6 Months'::text
            WHEN ("Tenure Months" <= 12) THEN '6-12 Months'::text
            WHEN ("Tenure Months" <= 24) THEN '1-2 Years'::text
            ELSE 'Over 2 Years'::text
        END AS tenure_bracket,
    count(*) AS total_customers,
    sum("Churn Value") AS churners
   FROM public.telco_cleaned
  GROUP BY
        CASE
            WHEN ("Tenure Months" <= 6) THEN '0-6 Months'::text
            WHEN ("Tenure Months" <= 12) THEN '6-12 Months'::text
            WHEN ("Tenure Months" <= 24) THEN '1-2 Years'::text
            ELSE 'Over 2 Years'::text
        END
  ORDER BY (sum("Churn Value")) DESC;


ALTER VIEW public.early_churn_window OWNER TO postgres;

--
-- Name: fiber_optic_red_flag; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.fiber_optic_red_flag AS
 SELECT "Internet Service",
    count("CustomerID") AS total_customers,
    sum("Churn Value") AS churn_count,
    round((avg("Churn Value") * (100)::numeric), 2) AS churn_rate_percentage
   FROM public.telco_cleaned
  GROUP BY "Internet Service"
  ORDER BY (round((avg("Churn Value") * (100)::numeric), 2)) DESC;


ALTER VIEW public.fiber_optic_red_flag OWNER TO postgres;

